create table sponsors (
    sponsor_id    number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    sponsor_name  varchar2(120 byte) not null enable,
    industry      varchar2(80 byte),
    contact_email varchar2(160 byte),
    active_flag   char(1 byte) default 'Y' not null enable
);

alter table sponsors
    add constraint sponsors_active_ck
        check ( active_flag in ( 'Y', 'N' ) ) enable;

alter table sponsors add constraint sponsors_name_uk unique ( sponsor_name )
    using index enable;

alter table sponsors
    add constraint sponsors_pk primary key ( sponsor_id )
        using index enable;


